#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int a,b,c,d; scanf("%d %d %d %d", &a, &b, &c, &d);
        int ans = (a>b?a:b) + (c>d?c:d);
        printf("%d\n", ans);
    }
    return 0;
}

